def run(cmd: str, cwd=None) -> None:
    """Run a shell command, exit if it fails."""
    result = subprocess.run(cmd.split(), cwd=cwd, capture_output=True, text=True)
    if result.returncode != 0:
        raise subprocess.CalledProcessError(result.returncode, cmd, output=result.stdout, stderr=result.stderr)


def build_stdlib(toolchain, opt_level):
    """
    Build Rust standard library using -Z build-std in a temporary project.
    """

    if (TARGET_STDLIB_DIR / f"{NIGHTLY_TO_STABLE[toolchain]}-O{opt_level}.a").exists():
        logger.info(f"Stdlib for {toolchain} with O{opt_level} already exists, skipping build.")
        return

    # Only use inline-llvm flag for versions >= 1.65.0
    stable_version = NIGHTLY_TO_STABLE[toolchain]
    version_parts = tuple(int(x) for x in stable_version.split("."))
    if version_parts >= (1, 65, 0):
        os.environ["RUSTFLAGS"] = "-Z inline-llvm=off"
    else:
        os.environ.pop("RUSTFLAGS", None)

    TARGET_STDLIB_DIR.mkdir(parents=True, exist_ok=True)

    with tempfile.TemporaryDirectory(prefix="rust_build_std_") as tmpdir:
        project_dir = Path(tmpdir) / "build_std_project"

        # Create project with cargo new
        run(f"rustup run {toolchain} cargo new {project_dir}")

        # Write release profile to Cargo.toml
        cargo_toml = project_dir / "Cargo.toml"
        with open(cargo_toml, "a") as f:
            f.write("\n[profile.release]\n")
            f.write("debug = true\n")
            if opt_level in ("s", "z"):
                f.write(f'opt-level = "{opt_level}"\n')
            else:
                f.write(f"opt-level = {opt_level}\n")

        # Build with -Z build-std
        build_cmd = f"rustup run {toolchain} cargo build --release"
        build_cmd += " -Z build-std=std --target x86_64-unknown-linux-gnu"

        run(build_cmd, cwd=project_dir)

        # Find the compiled std libraries in target directory
        target_deps_dir = project_dir / "target" / "x86_64-unknown-linux-gnu" / "release" / "deps"
        if not target_deps_dir.exists():
            return

        # Extract .o files from libstd, libcore, liballoc .rlib files
        extract_dir = project_dir / "extracted_objects"
        extract_dir.mkdir()

        for rlib in target_deps_dir.glob("*.rlib"):
            if rlib.name.startswith(("libstd-", "libcore-", "liballoc-")):
                rlib_extract_dir = extract_dir / rlib.stem
                rlib_extract_dir.mkdir()
                run(f"ar x {rlib}", cwd=rlib_extract_dir)

        # Collect all .o files and pack into a single .a file
        all_objects = list(extract_dir.glob("**/*.o"))

        output_archive = TARGET_STDLIB_DIR / f"{NIGHTLY_TO_STABLE[toolchain]}-O{opt_level}.a"
        TARGET_STDLIB_DIR.mkdir(parents=True, exist_ok=True)
        # Create archive with all .o files
        obj_list = " ".join(str(o) for o in all_objects)
        subprocess.run(f"ar rcs {output_archive} {obj_list}", shell=True, check=True)


def generate_flirt_sig(archive_file):
    """Generate FLIRT signature for a single .a archive file using pelf and sigmake."""
    archive_path = TARGET_STDLIB_DIR / archive_file
    sig_path = TARGET_FLIRT_SIGS_DIR / Path(archive_file).with_suffix(".sig")

    if sig_path.exists():
        logger.info(f"Signature for {archive_file} already exists, skipping.")
        return

    ida_dir = os.environ.get("IDA_DIR")
    if not ida_dir:
        raise RuntimeError("IDA_DIR environment variable is not set")

    pelf = os.path.join(ida_dir, "pelf")
    sigmake = os.path.join(ida_dir, "sigmake")

    # Generate .pat file using pelf
    pat_path = TARGET_FLIRT_SIGS_DIR / Path(archive_file).with_suffix(".pat")
    logger.info(f"Generating .pat for {archive_file}...")
    run(f"{pelf} {archive_path} {pat_path}")

    # Generate .sig file using sigmake
    logger.info(f"Generating .sig for {archive_file}...")
    try:
        run(f"{sigmake} {pat_path} {sig_path}")
    except subprocess.CalledProcessError:
        # Check if .exc file was generated
        exc_path = TARGET_FLIRT_SIGS_DIR / Path(archive_file).with_suffix(".exc")
        if exc_path.exists():
            logger.info(f"Found .exc file for {archive_file}, removing comments and retrying...")
            # Read .exc file and remove comment lines (starting with ;)
            with open(exc_path, "r") as f:
                lines = f.readlines()
            with open(exc_path, "w") as f:
                for line in lines:
                    if not line.strip().startswith(";"):
                        f.write(line)

            # Retry sigmake
            run(f"{sigmake} {pat_path} {sig_path}")

            # Clean up .exc file after successful generation
            exc_path.unlink(missing_ok=True)
        else:
            raise

    # Clean up .pat file
    pat_path.unlink(missing_ok=True)

    logger.info(f"Successfully generated signature for {archive_file}")


def generate_type_db(archive_file: Path, output_json: Path) -> None:
    """Generate type DB by extracting .a, parsing each .o, and merging results."""
    if not archive_file.exists():
        logger.warning(f"Archive not found: {archive_file}")
        return

    merged_functions = {}
    merged_structs = {}

    with tempfile.TemporaryDirectory(prefix="type_db_") as tmpdir:
        tmpdir_path = Path(tmpdir)
        run(f"ar x {archive_file}", cwd=tmpdir_path)

        for obj_file in tmpdir_path.glob("*.o"):
            obj_json = tmpdir_path / f"{obj_file.name}.json"
            try:
                run(f"{DWARF_PARSER_BIN} {obj_file} {obj_json}")
            except subprocess.CalledProcessError as e:
                logger.warning(f"dwarf_parser failed for {obj_file.name}: {e.stderr if e.stderr else str(e)}")
                continue

            if not obj_json.exists():
                continue

            try:
                with open(obj_json, "r") as f:
                    data = json.load(f)
            except Exception as e:
                logger.warning(f"Failed to load JSON for {obj_file.name}: {e}")
                continue

            functions = data.get("functions", {})
            structs = data.get("structs", {})

            for v in functions.values():
                del v["addr"]
                del v["local_variables"]
                merged_functions[v["name"]] = v
            for v in structs.values():
                merged_structs[v["name"]] = v

    merged_functions = list(merged_functions.values())
    merged_structs = list(merged_structs.values())

    output_json.parent.mkdir(parents=True, exist_ok=True)
    with open(output_json, "w") as f:
        json.dump({"functions": merged_functions, "structs": merged_structs}, f, separators=(",", ":"))


def install_toolchains(logger):
    """Install all required Rust toolchains and rust-src component."""
    unique_toolchains = list(NIGHTLY_TO_STABLE.keys())
    logger.info(f"Installing {len(unique_toolchains)} toolchains...")

    for i, toolchain in enumerate(unique_toolchains, 1):
        try:
            logger.info(f"[{i}/{len(unique_toolchains)}] Installing {toolchain}...")
            run(f"rustup install {toolchain} --profile minimal")
            run(f"rustup component add rust-src --toolchain {toolchain}")
        except subprocess.CalledProcessError as e:
            logger.warning(f"Failed to install {toolchain}: {e.stderr if e.stderr else str(e)}")
        except Exception as e:
            logger.warning(f"Error installing {toolchain}: {e}")

    logger.info("Toolchain installation complete.\n")


if __name__ == "__main__":
    # Setup logging
    logging.basicConfig(
        level=logging.INFO,
        format="%(asctime)s - %(levelname)s - %(message)s",
        handlers=[logging.FileHandler("gen_stdlib_db.log", mode="w"), logging.StreamHandler()],
    )
    logger = logging.getLogger(__name__)

    # Install all required toolchains first
    # install_toolchains(logger)

    opt_levels = ["0", "1", "2", "3", "s", "z"]

    # Build list of all tasks
    tasks = []
    for toolchain in NIGHTLY_TO_STABLE:
        for opt_level in opt_levels:
            tasks.append((toolchain, opt_level))

    total = len(tasks)
    failed_builds = []
    successful = 0

    logger.info(f"Starting {total} builds...")

    with ProcessPoolExecutor(max_workers=20) as executor:
        futures = {executor.submit(build_stdlib, tc, opt): (tc, opt) for tc, opt in tasks}

        for future in as_completed(futures):
            toolchain, opt_level = futures[future]
            try:
                future.result()
                successful += 1
                logger.info(f"[{successful + len(failed_builds)}/{total}] ✓ {toolchain} O{opt_level}")
            except subprocess.CalledProcessError as e:
                failed_builds.append((toolchain, opt_level, str(e)))
                logger.error(f"[{successful + len(failed_builds)}/{total}] ✗ {toolchain} O{opt_level}: {e}")
                if e.output:
                    logger.error(f"stdout: {e.output}")
                if e.stderr:
                    logger.error(f"stderr: {e.stderr}")
            except Exception as e:
                failed_builds.append((toolchain, opt_level, str(e)))
                logger.error(f"[{successful + len(failed_builds)}/{total}] ✗ {toolchain} O{opt_level}: {e}")
                logger.error(traceback.format_exc())

    logger.info(f"{'='*50}")
    logger.info(f"Build complete: {successful} succeeded, {len(failed_builds)} failed")

    if failed_builds:
        logger.info(f"Failed builds:")
        for toolchain, opt_level, error in failed_builds:
            logger.info(f"  - {toolchain} O{opt_level}: {error}")

    # Generate FLIRT signatures in parallel
    logger.info(f"\n{'='*50}")
    logger.info("Starting signature generation...")

    TARGET_FLIRT_SIGS_DIR.mkdir(parents=True, exist_ok=True)
    archive_files = [f for f in os.listdir(TARGET_STDLIB_DIR) if f.endswith(".a")]

    sig_total = len(archive_files)
    sig_failed = []
    sig_successful = 0

    with ProcessPoolExecutor(max_workers=20) as executor:
        sig_futures = {executor.submit(generate_flirt_sig, f): f for f in archive_files}

        for future in as_completed(sig_futures):
            archive_file = sig_futures[future]
            try:
                future.result()
                sig_successful += 1
                logger.info(f"[{sig_successful + len(sig_failed)}/{sig_total}] ✓ {archive_file}")
            except Exception as e:
                sig_failed.append((archive_file, str(e)))
                logger.error(f"[{sig_successful + len(sig_failed)}/{sig_total}] ✗ {archive_file}: {e}")
                logger.error(traceback.format_exc())

    logger.info(f"\n{'='*50}")
    logger.info(f"Signature generation complete: {sig_successful} succeeded, {len(sig_failed)} failed")

    if sig_failed:
        logger.info(f"Failed signatures:")
        for archive_file, error in sig_failed:
            logger.info(f"  - {archive_file}: {error}")

    TARGET_TYPE_DB_DIR.mkdir(parents=True, exist_ok=True)
    for version in RUST_VERSIONS:
        archive_file = TARGET_STDLIB_DIR / f"{version}-O3.a"
        type_db_file = TARGET_TYPE_DB_DIR / f"{version}.json"
        if type_db_file.exists():
            logger.info(f"Type DB for {version} already exists, skipping.")
            continue
        logger.info(f"Generating type DB for {version}...")
        generate_type_db(archive_file, type_db_file)
        logger.info(f"Generated type DB at {type_db_file}")
